+proptest! {
+    /// Delete reduces count by 1.
+    #[test]
+    fn delete_decrements_count(
+        items in prop::collection::vec(0..100000u64, 1..20)
+    ) {
+        let mut filter = CuckooFilter::with_capacity(100);
+        let mut inserted = Vec::new();
+
